create table dirkspzm32.isi_rave_reports_cfg (
    sid          varchar2(2 char) not null enable,
    firma_nr     number(6, 0) not null enable,
    kategorie    varchar2(100 char) not null enable,
    rave_projekt varchar2(255 char) not null enable,
    report_name  varchar2(100 char) not null enable,
    datenquelle  varchar2(10 char) default 'K' not null enable,
    beschreibung varchar2(255 char)
);

alter table dirkspzm32.isi_rave_reports_cfg
    add constraint pk_rave_reports_cfg
        primary key ( sid,
                      firma_nr,
                      kategorie,
                      rave_projekt,
                      report_name )
            using index enable;


